<?phpnamespace App\Http\Controllers;use Illuminate\Http\Request;use App\Http\Controllers\Controller;use Auth;use App\Models\User;use App\Models\Community;use App\Models\Household;use App\Models\AgricultureSystem;use App\Models\AgricultureHolderStatus;use App\Models\AgricultureSystemCycle;use App\Models\AgricultureHolder;use App\Models\AgricultureHolderSystem;use App\Models\AzollaType;use App\Models\AgricultureSharedHolder;use App\Models\AgricultureHolderDonor;use App\Models\Donor;use App\Helpers\AzollaSystemCalculator;use Illuminate\Support\Facades\DB;use App\Models\AgricultureInstallationType;use App\Exports\AgricultureHolderExport;use App\Exports\AgricultureHolderSmartboardExport;use App\Exports\AgricultureHolderCombinedExport;use Maatwebsite\Excel\Facades\Excel;use App\Models\AgricultureSystemComponent;use App\Models\AgricultureSystemComponentHolder;//Newuse Illuminate\Support\Facades\Storage;use BaconQrCode\Renderer\ImageRenderer;use BaconQrCode\Writer;use BaconQrCode\Renderer\RendererStyle\RendererStyle;use BaconQrCode\Renderer\Image\SvgImageBackEnd;class AgricultureUserController extends Controller{    /**     * Display a listing of the resource.     */    public function index(Request $request)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        try {            // Get agriculture holders by status with related data            $requestedHolders = AgricultureHolder::with([                'community',                 'household',                 'agricultureHolderStatus',                 'agricultureSystems.azollaType'            ])            ->whereHas('agricultureHolderStatus', function($query) {                $query->where('english_name', 'Requested');            })            ->where('is_archived', 0)            ->orderBy('requested_date', 'desc')            ->get();            $confirmedHolders = AgricultureHolder::with([                'community',                 'household',                 'agricultureHolderStatus',                 'agricultureSystems.azollaType'            ])            ->whereHas('agricultureHolderStatus', function($query) {                $query->where('english_name', 'Confirmed');            })            ->where('is_archived', 0)            ->orderBy('requested_date', 'desc')            ->get();            $progressHolders = AgricultureHolder::with([                'community',                 'household',                 'agricultureHolderStatus',                 'agricultureSystems.azollaType'            ])            ->whereHas('agricultureHolderStatus', function($query) {                $query->where('english_name', 'In Progress');                            })            ->where('is_archived', 0)            ->orderBy('requested_date', 'desc')            ->get();            $completedHolders = AgricultureHolder::with([                'community',                 'household',                 'agricultureHolderStatus',                 'agricultureSystems.azollaType'            ])            ->whereHas('agricultureHolderStatus', function($query) {                $query->where('english_name', 'Completed');            })            ->where('is_archived', 0)            ->orderBy('completed_date', 'desc')            ->get();                        return view('agriculture.user.index', compact(                'requestedHolders',                'confirmedHolders',                 'progressHolders',                'completedHolders'            ));                    } catch (\Exception $e) {            return back()->with('error', 'Error loading agriculture users: ' . $e->getMessage());        }    }    /**     * Determine contribution by system type (e.g. 'azolla_20') and installation type id (1=Easy,2=Medium,3=Hard).     */    private function determineContributionBySystemAndInstallation($systemType, $installationTypeId)    {        if (empty($systemType) || empty($installationTypeId)) return null;        // installationTypeId mapping: 1 => Easy, 2 => Medium (Misuim), 3 => Hard        $installKey = (int)$installationTypeId;        $map = [            // systemType => [ installId => amount ]            'azolla_20' => [1 => 250, 2 => 300, 3 => 350],            'azolla_50' => [1 => 300, 2 => 350, 3 => 350],            'azolla_100' => [1 => 350, 2 => 400, 3 => 450],        ];        $st = strtolower($systemType);        if (isset($map[$st]) && isset($map[$st][$installKey])) {            return $map[$st][$installKey];        }        // fallback: try to infer numeric size from systemType name        foreach (['100' => 'azolla_100', '50' => 'azolla_50', '20' => 'azolla_20'] as $num => $key) {            if (str_contains($st, (string)$num) && isset($map[$key][$installKey])) {                return $map[$key][$installKey];            }        }        return null;    }    /**     * Try to infer the primary system type assigned to a holder (returns string like 'azolla_50')     */    private function inferSystemTypeFromHolder(AgricultureHolder $holder)    {        try {            $sys = $holder->agricultureSystems()->first();            if (!$sys) return null;            // try azollaType relation first            if (method_exists($sys, 'azollaType') && $sys->azollaType) {                $name = strtolower($sys->azollaType->name ?? '');                if (str_contains($name, '20')) return 'azolla_20';                if (str_contains($name, '50')) return 'azolla_50';                if (str_contains($name, '100')) return 'azolla_100';            }            // fallback to system name            $name = strtolower($sys->name ?? '');            if (str_contains($name, '20')) return 'azolla_20';            if (str_contains($name, '50')) return 'azolla_50';            if (str_contains($name, '100')) return 'azolla_100';        } catch (\Exception $e) {            return null;        }        return null;    }    /**     * Determine a system type key (azolla_20|azolla_50|azolla_100) from an AgricultureSystem model.     */    private function getSystemTypeFromSystem($system)    {        try {            if (method_exists($system, 'azollaType') && $system->azollaType) {                $name = strtolower($system->azollaType->name ?? '');                if (str_contains($name, '20')) return 'azolla_20';                if (str_contains($name, '50')) return 'azolla_50';                if (str_contains($name, '100')) return 'azolla_100';            }            $name = strtolower($system->name ?? '');            if (str_contains($name, '20')) return 'azolla_20';            if (str_contains($name, '50')) return 'azolla_50';            if (str_contains($name, '100')) return 'azolla_100';        } catch (\Exception $e) {            return null;        }        return null;    }    /**     * Sum contribution amounts for all systems assigned to a holder (runtime only).     * Returns integer total or null if cannot compute.     */    private function totalContributionForHolder(AgricultureHolder $holder, $installationTypeId)    {        try {            $systems = $holder->agricultureSystems()->where('is_archived', 0)->get();            if (!$systems || $systems->count() === 0) {                return null;            }            $total = 0;            $any = false;            foreach ($systems as $sys) {                $stype = $this->getSystemTypeFromSystem($sys);                if (!$stype) continue;                $amt = $this->determineContributionBySystemAndInstallation($stype, $installationTypeId);                if ($amt !== null) {                    $total += $amt;                    $any = true;                }            }            return $any ? $total : null;        } catch (\Exception $e) {            return null;        }    }    /**     * Generate and store a QR code image (SVG) for a given holder and return it.     */    public function qrcode(Request $request, $id)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        try {            $holder = AgricultureHolder::findOrFail($id);            // If QR already exists and file is present, serve it            if (!empty($holder->qrcode_path) && Storage::disk('public')->exists($holder->qrcode_path)) {                $fullPath = storage_path('app/public/' . $holder->qrcode_path);                return response()->file($fullPath);            }            // Text encoded in QR: link to the holder show page (can be changed)            $text = route('argiculture-user.show', $id);            // Render SVG QR using BaconQrCode            $renderer = new ImageRenderer(                new RendererStyle(300),                new SvgImageBackEnd()            );            $writer = new Writer($renderer);            $svg = $writer->writeString($text);            // Save to storage/app/public/agriculture_qrcodes/ with holder and community in filename            $dir = 'agriculture_qrcodes';            $holderName = $holder->household->english_name ?? ('holder_' . $holder->id);            $communityName = $holder->community->english_name ?? ($holder->community->name ?? 'community');            $holderSlug = $this->sanitizeFileNameComponent($holderName);            $communitySlug = $this->sanitizeFileNameComponent($communityName);            $filename = 'holder_' . $holderSlug . '_' . $communitySlug . '_' . $id . '_' . time() . '.svg';            $path = $dir . '/' . $filename;            Storage::disk('public')->put($path, $svg);            // Persist path to model            $holder->qrcode_path = $path;            $holder->save();    //         // Try to convert SVG to JPEG for easier downloading/viewing    //         $jpegUrl = null;    //         try {    //             if (class_exists('\Imagick')) {    //                 $imagick = new \Imagick();    //                 // Read SVG from string    //                 $imagick->readImageBlob($svg);    //                 // Set white background for JPEG    //                 $imagick->setImageBackgroundColor('white');    //                 if (method_exists($imagick, 'mergeImageLayers')) {    //                     $imagick = $imagick->mergeImageLayers(\Imagick::LAYERMETHOD_FLATTEN);    //                 }    //                 $imagick->setImageFormat('jpeg');    //                 $imagick->setImageCompressionQuality(85);    //                 $jpegBlob = $imagick->getImageBlob();    //                 $jpgFilename = 'holder_' . $holderSlug . '_' . $communitySlug . '_' . $id . '_' . time() . '.jpg';    //                 $jpgPath = $dir . '/' . $jpgFilename;    //                 Storage::disk('public')->put($jpgPath, $jpegBlob);    //                 $jpegUrl = Storage::url($jpgPath);    //             }    //         } catch (\Exception $e) {    //             // If conversion fails, ignore and continue returning SVG    //             $jpegUrl = null;    //         }    //         // If request is AJAX, return the SVG content    //         if ($request->ajax()) {    //             $response = ['success' => true, 'url' => Storage::url($path)];    //             if ($jpegUrl) $response['jpeg_url'] = $jpegUrl;    //             return response()->json($response);    //         }    //         // Non-AJAX: return SVG file    //         return response($svg, 200)->header('Content-Type', 'image/svg+xml');        } catch (\Exception $e) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'Error generating QR: ' . $e->getMessage()], 500);            }            return back()->with('error', 'Error generating QR code: ' . $e->getMessage());      }    }    /**     * JSON endpoint for QR code - returns existing QR URL or generates and returns URL.     * This is intended for AJAX/frontend calls to show a preview/download and to ensure     * QR is generated only once per holder.     */    public function qrcodeJson(Request $request, $id)    {        if (!Auth::guard('user')->user()) {            return response()->json(['success' => false, 'message' => 'Unauthorized'], 401);        }        try {            $holder = AgricultureHolder::findOrFail($id);            // If QR already exists and file is present, return its public URL and an inline data URL            if (!empty($holder->qrcode_path) && Storage::disk('public')->exists($holder->qrcode_path)) {                $path = $holder->qrcode_path;                $url = Storage::url($path);                $dataUrl = null;                try {                    $fullPath = storage_path('app/public/' . $path);                    $contents = file_get_contents($fullPath);                    $ext = strtolower(pathinfo($fullPath, PATHINFO_EXTENSION));                    if ($ext === 'svg') {                        $dataUrl = 'data:image/svg+xml;charset=utf-8;base64,' . base64_encode($contents);                    } else {                        $mime = $ext === 'jpg' || $ext === 'jpeg' ? 'image/jpeg' : 'application/octet-stream';                        $dataUrl = 'data:' . $mime . ';base64,' . base64_encode($contents);                    }                } catch (\Exception $e) {                    $dataUrl = null;                }                // Use Household's comet_id when available and include community name                $householdCometId = null;                $holderName = null;                $communityName = null;                try {                    if ($holder->household) {                        $householdCometId = $holder->household->comet_id ?? $holder->household->id;                        $holderName = $holder->household->english_name ?? null;                        $communityName = $holder->community->english_name ?? ($holder->community->name ?? null);                    }                } catch (\Exception $e) {                    $householdCometId = null;                    $holderName = null;                    $communityName = null;                }                return response()->json([                    'success' => true,                    'exists' => true,                    'url' => $url,                    'data_url' => $dataUrl,                    'comet_id' => $householdCometId ?? $holder->id,                    'holder_name' => $holderName ?? ('holder_' . $holder->id),                    'community_name' => $communityName ?? null                ]);                            }            // Otherwise generate SVG QR and save once (same behavior as qrcode())            $text = route('argiculture-user.show', $id);            $renderer = new ImageRenderer(                new RendererStyle(300),                new SvgImageBackEnd()            );            $writer = new Writer($renderer);            $svg = $writer->writeString($text);            $dir = 'agriculture_qrcodes';            $holderName = $holder->household->english_name ?? ('holder_' . $holder->id);            $communityName = $holder->community->english_name ?? ($holder->community->name ?? 'community');            $holderSlug = $this->sanitizeFileNameComponent($holderName);            $communitySlug = $this->sanitizeFileNameComponent($communityName);            $filename = 'holder_' . $holderSlug . '_' . $communitySlug . '_' . $id . '_' . time() . '.svg';            $path = $dir . '/' . $filename;            Storage::disk('public')->put($path, $svg);            // Persist path to model and save            $holder->qrcode_path = $path;            $holder->save();            // // Prepare data URL (prefer JPEG if we can convert, otherwise SVG inline)            // $jpegUrl = null;            // $dataUrl = null;            // try {            //     if (class_exists('\Imagick')) {            //         $imagick = new \Imagick();            //         $imagick->readImageBlob($svg);            //         $imagick->setImageBackgroundColor('white');            //         if (method_exists($imagick, 'mergeImageLayers')) {            //             $flat = $imagick->mergeImageLayers(\Imagick::LAYERMETHOD_FLATTEN);            //         } else {            //             $flat = $imagick;            //         }            //         $flat->setImageFormat('jpeg');            //         $flat->setImageCompressionQuality(85);            //         $jpegBlob = $flat->getImageBlob();            //         $jpgFilename = 'holder_' . $holderSlug . '_' . $communitySlug . '_' . $id . '_' . time() . '.jpg';            //         $jpgPath = $dir . '/' . $jpgFilename;            //         Storage::disk('public')->put($jpgPath, $jpegBlob);            //         $jpegUrl = Storage::url($jpgPath);            //         $dataUrl = 'data:image/jpeg;base64,' . base64_encode($jpegBlob);            //     }            // } catch (\Exception $e) {            //     // conversion failed — we'll fall back to SVG data URL            //     $dataUrl = null;            // }            // if (!$dataUrl) {            //     $dataUrl = 'data:image/svg+xml;charset=utf-8;base64,' . base64_encode($svg);            // }            // Use Household's comet_id when available            $householdCometId = null;            $holderName = null;            try {                if ($holder->household) {                    $householdCometId = $holder->household->comet_id ?? $holder->household->id;                    $holderName = $holder->household->english_name ?? null;                }            } catch (\Exception $e) {                $householdCometId = null;                $holderName = null;            }            $response = [                            'success' => true,                            'exists' => false,                            'url' => Storage::url($path),                            'data_url' => $dataUrl,                            'comet_id' => $householdCometId ?? $holder->id,                            'holder_name' => $holderName ?? ('holder_' . $holder->id)                        ];                        if (!empty($jpegUrl)) $response['jpeg_url'] = $jpegUrl;            return response()->json($response);        } catch (\Exception $e) {            return response()->json(['success' => false, 'message' => 'Error generating QR: ' . $e->getMessage()], 500);        }    }    /**     * Show the form for creating a new resource.     */    public function create()    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14])) {            return back()->with('error', 'You do not have permission to create agriculture users.');        }        try {            $communities = Community::where('is_archived', 0)                ->orderBy('english_name', 'ASC')                ->get();                            $households = Household::where('is_archived', 0)                ->orderBy('english_name', 'ASC')                ->get();            $people = User::select('id', 'name')->orderBy('name', 'ASC')->get();            $donors = Donor::where('is_archived', 0)->orderBy('donor_name', 'ASC')->get();            // Fetch agriculture installation types using the model            $agricultureInstallationTypes = AgricultureInstallationType::where('is_archived', 0)                ->orderBy('id', 'asc')                ->get();            // Fetch agriculture system cycles            $agricultureSystemCycles = AgricultureSystemCycle::orderBy('name', 'ASC')->get();            // Fetch existing agriculture systems to allow explicit selection in the create form            $agricultureSystems = AgricultureSystem::where('is_archived', 0)->orderBy('name', 'ASC')->get();            return view('agriculture.user.create', compact(                'communities',                 'households',                'people',                'donors',                'agricultureInstallationTypes',                'agricultureSystemCycles',                'agricultureSystems'            ));                    } catch (\Exception $e) {            return back()->with('error', 'Error loading form data: ' . $e->getMessage());        }    }    /**     * Store a newly created resource in storage.     */    public function store(Request $request)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14])) {            return back()->with('error', 'You do not have permission to create agriculture users.');        }        // Enhanced validation with herd size requirement        $request->validate([            'community_id' => 'required|exists:communities,id',            'household_id' => 'required|exists:households,id',            'agriculture_installation_type_id' => 'nullable|exists:agriculture_installation_types,id',            'agriculture_system_cycle_id' => 'nullable|exists:agriculture_system_cycles,id',            'size_of_herds' => 'required|integer|min:1|max:10000', // Required field for herd size            'azolla_unit' => 'nullable|integer|min:0', // Auto-calculated, not required input            'size_of_goat' => 'nullable|integer|min:0',            'size_of_cow' => 'nullable|integer|min:0',            'size_of_camel' => 'nullable|integer|min:0',            'size_of_chicken' => 'nullable|integer|min:0',            'requested_date' => 'nullable|date',            'completed_date' => 'nullable|date|after_or_equal:requested_date',            'contribution_rate' => 'nullable|numeric|min:0',            'area' => 'nullable|string|max:255',            'area_of_installation' => 'nullable|string|in:A,B,C',            'alternative_area' => 'nullable|string|max:1000',            'notes' => 'nullable|string|max:1000'            ,            // allow user to explicitly select one or more existing systems by id            'selected_system_ids' => 'nullable|array',            'selected_system_ids.*' => 'integer|exists:agriculture_systems,id'            ,            'manual_entry' => 'nullable|boolean'        ], [            'size_of_herds.required' => 'Herd size is required to calculate systems automatically.',            'size_of_herds.min' => 'Herd size must be at least 1 sheep.',            'size_of_herds.max' => 'Herd size cannot exceed 10,000 sheep.',            'completed_date.after_or_equal' => 'Completed date cannot be before requested date.'        ]);        try {            DB::beginTransaction();                        // Get herd size and validate business rules            $herdSize = (int) $request->size_of_herds;            $calculationSummary = AzollaSystemCalculator::generateCalculationSummary($herdSize);                        // Check for validation errors from business rules            if (!$calculationSummary['is_valid']) {                return back()->withInput()                    ->with('error', 'Herd size validation failed: ' . implode(', ', $calculationSummary['validation_errors']));            }            // Find the "Requested" status (create it if it doesn't exist)            $requestedStatus = AgricultureHolderStatus::firstOrCreate(                ['english_name' => 'Requested'],                [                    'english_name' => 'Requested',                    'arabic_name' => 'مطلوب', // Arabic translation                    'comet_id' => 'AGR_STATUS_REQ_' . time()                ]            );            // Determine azolla units: use manual value when provided, otherwise auto-calc            if ($request->has('manual_entry') && $request->filled('azolla_unit')) {                $azollaUnits = (int) $request->azolla_unit;            } else {                $azollaUnits = AzollaSystemCalculator::calculateAzollaUnits($herdSize);            }                        // Get the default agriculture system cycle before creating the holder            $defaultCycle = $this->getDefaultAgricultureSystemCycle();                        // Create AgricultureHolder record with "Requested" status            $agricultureHolder = AgricultureHolder::create([                'community_id' => $request->community_id,                'household_id' => $request->household_id,                'agriculture_holder_status_id' => $requestedStatus->id,                'agriculture_system_cycle_id' => $request->input('agriculture_system_cycle_id') ?? $defaultCycle->id, // allow override from form                'agriculture_installation_type_id' => $request->input('agriculture_installation_type_id') ?? $request->input('agriculture_installation_types_id') ?? null,                'azolla_unit' => $azollaUnits, // Auto-calculated                'size_of_herds' => $herdSize,                'size_of_goat' => $request->size_of_goat ?? 0,                'size_of_cow' => $request->size_of_cow ?? 0,                'size_of_camel' => $request->size_of_camel ?? 0,                'size_of_chicken' => $request->size_of_chicken ?? 0,                'requested_date' => $request->requested_date ?? now(),                'area_of_installation' => $request->input('area_of_installation') ?? null,                'completed_date' => $request->completed_date,                // contribution amount is computed at runtime (not stored in DB)                'area' => $request->area,                'alternative_area' => $request->alternative_area,                'notes' => $request->notes            ]);            // Assign systems according to user's explicit selection or automatic calculation.            if ($request->has('selected_system_ids') && is_array($request->input('selected_system_ids')) && count($request->input('selected_system_ids')) > 0) {                $systemsCreated = $this->assignSelectedSystems($agricultureHolder, $request->input('selected_system_ids'));            } elseif ($request->has('manual_entry')) {                // Manual entry requested: do not auto-assign systems. Leave systems unassigned unless user selected them.                $systemsCreated = 0;            } else {                // Save system requirements to agriculture_holder_systems based on calculation                $systemsCreated = $this->saveSystemRequirements($agricultureHolder, $calculationSummary['systems']);            }            // Only throw when we expected auto-assignment but got none            if (!$request->has('selected_system_ids') && !$request->has('manual_entry') && $systemsCreated === 0) {                throw new \Exception('No system requirements were saved. Please check the calculation logic.');            }            // Persist shared herd information if present in the form            if ($request->has('shared_herd') && intval($request->input('number_of_people', 0)) > 0) {                $numberOfPeople = intval($request->input('number_of_people'));                for ($i = 1; $i <= $numberOfPeople; $i++) {                    $householdField = 'household_' . $i . '_name';                    $sheepField = 'household_' . $i . '_sheep';                    $householdId = $request->input($householdField);                    $sheepCount = intval($request->input($sheepField, 0));                    // Resolve household name when household id is provided                    $householdName = null;                    if ($householdId) {                        $hh = Household::find($householdId);                        if ($hh) {                            $householdName = $hh->english_name;                        }                    }                    // Create record in the existing table: agriculture_holder_id, household_id, size_of_herds, is_archived                    // size_of_herds is required by the DB, so store the sheep count (0 allowed)                    AgricultureSharedHolder::create([                        'agriculture_holder_id' => $agricultureHolder->id,                        'household_id' => $householdId ?: null,                        'size_of_herds' => $sheepCount,                        'is_archived' => 0                    ]);                }            }            // Persist donors if provided (agriculture_holder_donors)            if ($request->has('donor_herd') || $request->has('number_of_donors')) {                $numDonors = intval($request->input('number_of_donors', 0));                for ($d = 1; $d <= $numDonors; $d++) {                    $donorField = 'donor_' . $d . '_id';                    $donorId = $request->input($donorField);                    if ($donorId) {                        AgricultureHolderDonor::create([                            'agriculture_holder_id' => $agricultureHolder->id,                            'donor_id' => $donorId                        ]);                    }                }            }            DB::commit();                        $successMessage = sprintf(                'Agriculture Holder created successfully with "Requested" status! Generated %d Azolla units and assigned %d existing systems for %d sheep.',                $azollaUnits,                $systemsCreated,                $herdSize            );                        return redirect()->route('argiculture-user.index')                ->with('message', $successMessage);                        } catch (\Exception $e) {            DB::rollBack();            return back()->withInput()                ->with('error', 'Error creating agriculture user: ' . $e->getMessage());        }    }    /**     * Assign existing agriculture systems to holder based on calculated requirements     *     * @param AgricultureHolder $holder     * @param array $systemsNeeded     * @return int Number of systems assigned     */    private function saveSystemRequirements(AgricultureHolder $holder, array $systemsNeeded): int    {        $systemsAssigned = 0;                foreach ($systemsNeeded as $index => $systemRequirement) {            // Find existing agriculture system based on system type            $existingSystem = $this->findExistingAgricultureSystem($systemRequirement['system_type']);                        if ($existingSystem) {                // Assign existing system to holder                AgricultureHolderSystem::create([                    'agriculture_holder_id' => $holder->id,                    'agriculture_system_id' => $existingSystem->id,                    'is_archived' => 0                ]);                // Copy system components into holder-specific table so user can have different values                // Detect actual FK/archived column names in case the schema changed                try {                    $cols = \Schema::getColumnListing('agriculture_system_components');                } catch (\Exception $e) {                    $cols = [];                }                $systemCol = null; $archivedCol = null;                foreach ($cols as $col) {                    $lc = strtolower($col);                    if (!$systemCol && str_contains($lc, 'system') && str_ends_with($lc, '_id')) $systemCol = $col;                    if (!$archivedCol && ($lc === 'is_archived' || $lc === 'archived')) $archivedCol = $col;                }                $systemCol = $systemCol ?? 'agriculture_system_id';                $archivedCol = $archivedCol ?? 'is_archived';                $components = \DB::table('agriculture_system_components as asc')                    ->where("asc.{$systemCol}", $existingSystem->id)                    ->where("asc.{$archivedCol}", 0)                    ->get();                foreach ($components as $component) {                    AgricultureSystemComponentHolder::create([                        'agriculture_system_component_id' => $component->id,                        'agriculture_holder_id' => $holder->id,                        'quantity' => $component->quantity,                        'unit_price' => $component->unit_price,                        'is_archived' => 0                    ]);                }                $systemsAssigned++;            }        }                return $systemsAssigned;    }    /**     * Find existing agriculture system based on system type     *     * @param string $systemType     * @return AgricultureSystem|null     */    private function findExistingAgricultureSystem(string $systemType): ?AgricultureSystem    {        // Map system types to existing agriculture_system IDs (preferred lookup by id)        // Adjust the IDs below to match the actual IDs in your `agriculture_systems` table.        $systemMapping = [            'azolla_20' => 3,   // previously 'Azolla 20 units'            'azolla_50' => 4,   // previously 'Azolla 50 units'            'azolla_100' => 5   // previously 'Azolla 100 units'        ];        $systemId = $systemMapping[$systemType] ?? null;        if ($systemId) {            return AgricultureSystem::where('id', $systemId)                ->where('is_archived', 0)                ->first();        }        return null;    }    /**     * Assign specific existing agriculture systems (by id) to a holder and copy components.     *     * @param AgricultureHolder $holder     * @param array $systemIds     * @return int Number of systems assigned     */    private function assignSelectedSystems(AgricultureHolder $holder, array $systemIds): int    {        $systemsAssigned = 0;        foreach ($systemIds as $sid) {            try {                $existingSystem = AgricultureSystem::where('id', intval($sid))->where('is_archived', 0)->first();                if (!$existingSystem) continue;                AgricultureHolderSystem::create([                    'agriculture_holder_id' => $holder->id,                    'agriculture_system_id' => $existingSystem->id,                    'is_archived' => 0                ]);                // Copy components into holder-specific table                try {                    $cols = \Schema::getColumnListing('agriculture_system_components');                } catch (\Exception $e) {                    $cols = [];                }                $systemCol = null; $archivedCol = null;                foreach ($cols as $col) {                    $lc = strtolower($col);                    if (!$systemCol && str_contains($lc, 'system') && str_ends_with($lc, '_id')) $systemCol = $col;                    if (!$archivedCol && ($lc === 'is_archived' || $lc === 'archived')) $archivedCol = $col;                }                $systemCol = $systemCol ?? 'agriculture_system_id';                $archivedCol = $archivedCol ?? 'is_archived';                $components = \DB::table('agriculture_system_components as asc')                    ->where("asc.{$systemCol}", $existingSystem->id)                    ->where("asc.{$archivedCol}", 0)                    ->get();                foreach ($components as $component) {                    AgricultureSystemComponentHolder::create([                        'agriculture_system_component_id' => $component->id,                        'agriculture_holder_id' => $holder->id,                        'quantity' => $component->quantity,                        'unit_price' => $component->unit_price,                        'is_archived' => 0                    ]);                }                $systemsAssigned++;            } catch (\Exception $e) {                // ignore and continue with next id                continue;            }        }        return $systemsAssigned;    }    /**     * Get or create Azolla Type based on system type     */    private function getOrCreateAzollaType(string $systemType): AzollaType    {        $typeMapping = [            'azolla_20' => ['name' => 'Azolla 20 Unit', 'description' => 'Supports 1-20 sheep'],            'azolla_50' => ['name' => 'Azolla 50 Unit', 'description' => 'Supports 21-50 sheep'],            'azolla_100' => ['name' => 'Azolla 100 Unit', 'description' => 'Supports 51-100 sheep']        ];        $typeData = $typeMapping[$systemType] ?? $typeMapping['azolla_20'];                return AzollaType::firstOrCreate(            ['name' => $typeData['name']],            [                'name' => $typeData['name'],                'description' => $typeData['description'],                'is_archived' => 0            ]        );    }    /**     * Get the default agriculture system cycle     */    private function getDefaultAgricultureSystemCycle(): AgricultureSystemCycle    {        // Try to get an existing cycle, or create a default one        return AgricultureSystemCycle::firstOrCreate(            ['name' => 'Standard Cycle'],            [                'name' => 'Standard Cycle',                'description' => 'Default agriculture system cycle for new systems',                'is_archived' => 0            ]        );    }    /**     * Sanitize a string to be safely included in a filename.     */    private function sanitizeFileNameComponent(string $str): string    {        $str = mb_strtolower(trim($str));        $str = preg_replace('/[^\p{L}\p{Nd}\s_-]+/u', '', $str);        $str = preg_replace('/\s+/', '_', $str);        $str = preg_replace('/_+/', '_', $str);        $str = preg_replace('/[^a-z0-9_-]/', '', $str);        $str = substr($str, 0, 50);        return $str ?: 'unknown';    }    /**     * Display the specified resource.     */    public function show($id)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        try {            // Load the real agriculture holder with related data            $agricultureUser = AgricultureHolder::with([                'community',                'household',                'agricultureHolderStatus',                'agricultureSystems.azollaType',                'agricultureSharedHolders.household'            ])->findOrFail($id);            // Also fetch shared herd rows directly from DB as a fallback (in case of relation issues)            $sharedHerds = DB::table('agriculture_shared_holders')                ->where('agriculture_holder_id', $agricultureUser->id)                ->orderBy('id', 'asc')                ->get();            // Also fetch donors for this holder            $holderDonors = AgricultureHolderDonor::with('donor')                ->where('agriculture_holder_id', $agricultureUser->id)                ->orderBy('id', 'asc')                ->get();            // compute contribution amount at runtime (do not store in DB)            $contributionAmount = $this->totalContributionForHolder(                $agricultureUser,                $agricultureUser->agriculture_installation_type_id            );            // also prepare a per-system breakdown so we can inspect why total may be null            $contributionBreakdown = [];            try {                $systems = $agricultureUser->relationLoaded('agricultureSystems') ? $agricultureUser->agricultureSystems : $agricultureUser->agricultureSystems()->where('is_archived', 0)->get();                foreach ($systems as $sys) {                    $stype = $this->getSystemTypeFromSystem($sys);                    $amt = $this->determineContributionBySystemAndInstallation($stype, $agricultureUser->agriculture_installation_type_id);                    $contributionBreakdown[] = [                        'system_id' => $sys->id ?? null,                        'system_name' => $sys->name ?? ($sys->azollaType->name ?? '—'),                        'system_type' => $stype,                        'amount' => $amt                    ];                }            } catch (\Exception $e) {                $contributionBreakdown = [];            }            return view('agriculture.user.show', compact('agricultureUser', 'sharedHerds', 'holderDonors', 'contributionAmount', 'contributionBreakdown'));        } catch (\Exception $e) {            return back()->with('error', 'Agriculture user not found.');        }    }    /**     * Show the form for editing the specified resource.     */    public function edit($id)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14])) {            return back()->with('error', 'You do not have permission to edit agriculture users.');        }        try {            // Load the real agriculture holder for editing            $agricultureUser = AgricultureHolder::with([                'community',                'household',                'agricultureSharedHolders',                'agricultureHolderDonors.donor'            ])->findOrFail($id);            $donors = Donor::where('is_archived', 0)->orderBy('donor_name', 'ASC')->get();                        $communities = Community::where('is_archived', 0)                ->orderBy('english_name', 'ASC')                ->get();                            $households = Household::where('is_archived', 0)                ->orderBy('english_name', 'ASC')                ->get();            $agricultureSystems = AgricultureSystem::where('is_archived', 0)                ->orderBy('name', 'ASC')                ->get();            $agricultureHolderStatuses = AgricultureHolderStatus::orderBy('english_name', 'ASC')                ->get();            $agricultureSystemCycles = AgricultureSystemCycle::orderBy('name', 'ASC')                ->get();            // also load installation types for edit view via model            $agricultureInstallationTypes = AgricultureInstallationType::where('is_archived', 0)                ->orderBy('id', 'asc')                ->get();            return view('agriculture.user.edit', compact(                'agricultureUser',                 'communities',                 'households',                 'agricultureSystems',                 'agricultureHolderStatuses',                 'agricultureSystemCycles',                'donors',                'agricultureInstallationTypes'            ));                    } catch (\Exception $e) {            return back()->with('error', 'Agriculture user not found.');        }    }    /**     * Update the specified resource in storage.     */    public function update(Request $request, $id)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14])) {            return back()->with('error', 'You do not have permission to update agriculture users.');        }        // Validate main fields        $request->validate([            'community_id' => 'nullable|exists:communities,id',            'household_id' => 'nullable|exists:households,id',            // accept either singular or plural field name from the form            'agriculture_installation_type_id' => 'nullable|exists:agriculture_installation_types,id',            'area_of_installation' => 'nullable|string|in:A,B,C',            'agriculture_system_cycle_id' => 'nullable|exists:agriculture_system_cycles,id',            'size_of_herds' => 'nullable|integer|min:0|max:10000',            'size_of_goat' => 'nullable|integer|min:0',            'size_of_cow' => 'nullable|integer|min:0',            'size_of_camel' => 'nullable|integer|min:0',            'size_of_chicken' => 'nullable|integer|min:0',            'requested_date' => 'nullable|date',            'completed_date' => 'nullable|date|after_or_equal:requested_date',            'contribution_rate' => 'nullable|numeric|min:0',            'area' => 'nullable|string|max:255',            'alternative_area' => 'nullable|string|max:1000',            'notes' => 'nullable|string|max:1000',            'shared_herd' => 'nullable',            'number_of_people' => 'nullable|integer|min:0'            // Optional systems payload submitted from the edit form as hidden inputs            ,'systems' => 'nullable|array',            'systems.*.system_type' => 'nullable|string|in:azolla_20,azolla_50,azolla_100'            ,            // allow explicit selection of existing systems on edit            'selected_system_ids' => 'nullable|array',            'selected_system_ids.*' => 'integer|exists:agriculture_systems,id'            ,            'manual_entry' => 'nullable|boolean'        ]);        try {            DB::beginTransaction();            $holder = AgricultureHolder::findOrFail($id);            // Update holder fields            $holder->update([                'community_id' => $request->community_id,                'household_id' => $request->household_id,                'agriculture_installation_type_id' => $request->input('agriculture_installation_type_id') ?? $request->input('agriculture_installation_types_id') ?? $holder->agriculture_installation_type_id,                'area_of_installation' => $request->area_of_installation ?? $holder->area_of_installation,                'agriculture_system_cycle_id' => $request->agriculture_system_cycle_id ?? $holder->agriculture_system_cycle_id,                'size_of_herds' => $request->size_of_herds ?? $holder->size_of_herds,                'size_of_goat' => $request->size_of_goat ?? $holder->size_of_goat,                'size_of_cow' => $request->size_of_cow ?? $holder->size_of_cow,                'size_of_camel' => $request->size_of_camel ?? $holder->size_of_camel,                'size_of_chicken' => $request->size_of_chicken ?? $holder->size_of_chicken,                'requested_date' => $request->requested_date ?? $holder->requested_date,                'completed_date' => $request->completed_date ?? $holder->completed_date,                // contribution amount is computed at runtime (not stored in DB)                'area' => $request->area ?? $holder->area,                'alternative_area' => $request->alternative_area ?? $holder->alternative_area,                'notes' => $request->notes ?? $holder->notes            ]);            // If user explicitly selected systems in the edit form, use those selections            if ($request->has('selected_system_ids') && is_array($request->input('selected_system_ids')) && count($request->input('selected_system_ids')) > 0) {                AgricultureHolderSystem::where('agriculture_holder_id', $holder->id)->delete();                $systemsCreated = $this->assignSelectedSystems($holder, $request->input('selected_system_ids'));            } elseif ($request->has('manual_entry')) {                // Manual entry requested: do not alter existing system assignments. Update azolla_unit if provided.                if ($request->filled('azolla_unit')) {                    $holder->azolla_unit = (int) $request->azolla_unit;                    $holder->save();                }            } else {                // Recalculate systems and azolla units when herd size changed or provided                $herdSizeForCalc = intval($request->input('size_of_herds', $holder->size_of_herds ?? 0));                if ($herdSizeForCalc > 0) {                    $calculationSummary = AzollaSystemCalculator::generateCalculationSummary($herdSizeForCalc);                    if (!$calculationSummary['is_valid']) {                        // rollback will be handled in catch; throw to surface validation                        throw new \Exception('Herd size validation failed: ' . implode(', ', $calculationSummary['validation_errors']));                    }                    // Remove any existing holder-system assignments and save new requirements                    AgricultureHolderSystem::where('agriculture_holder_id', $holder->id)->delete();                    $systemsCreated = $this->saveSystemRequirements($holder, $calculationSummary['systems']);                                        // Update azolla units on holder                    $holder->azolla_unit = $calculationSummary['azolla_units'];                    $holder->save();                }            }            // Replace shared herd rows: delete existing and recreate from form            if ($request->has('shared_herd')) {                AgricultureSharedHolder::where('agriculture_holder_id', $holder->id)->delete();                $numberOfPeople = intval($request->input('number_of_people', 0));                for ($i = 1; $i <= $numberOfPeople; $i++) {                    $householdField = 'household_' . $i . '_name';                    $sheepField = 'household_' . $i . '_sheep';                    $householdId = $request->input($householdField);                    $sheepCount = intval($request->input($sheepField, 0));                    AgricultureSharedHolder::create([                        'agriculture_holder_id' => $holder->id,                        'household_id' => $householdId ?: null,                        'size_of_herds' => $sheepCount,                        'is_archived' => 0                    ]);                }            } else {                // If shared_herd unchecked, remove existing shared rows                AgricultureSharedHolder::where('agriculture_holder_id', $holder->id)->delete();            }            // Replace donors for this holder            if ($request->has('donor_herd')) {                AgricultureHolderDonor::where('agriculture_holder_id', $holder->id)->delete();                $numDonors = intval($request->input('number_of_donors', 0));                for ($d = 1; $d <= $numDonors; $d++) {                    $donorField = 'donor_' . $d . '_id';                    $donorId = $request->input($donorField);                    if ($donorId) {                        AgricultureHolderDonor::create([                            'agriculture_holder_id' => $holder->id,                            'donor_id' => $donorId                        ]);                    }                }            } else {                AgricultureHolderDonor::where('agriculture_holder_id', $holder->id)->delete();            }            DB::commit();            return redirect()->route('argiculture-user.index')                ->with('message', 'Agriculture User updated successfully!');        } catch (\Exception $e) {            DB::rollBack();            return back()->withInput()                ->with('error', 'Error updating agriculture user: ' . $e->getMessage());        }    }    /**     * Remove the specified resource from storage.     */    public function destroy($id)    {        if (!Auth::guard('user')->user()) {            if (request()->ajax()) {                return response()->json(['success' => false, 'message' => 'Unauthorized'], 401);            }            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            if (request()->ajax()) {                return response()->json(['success' => false, 'message' => 'Unauthorized'], 403);            }            return back()->with('error', 'You do not have permission to delete agriculture users.');        }        try {            DB::beginTransaction();            $holder = AgricultureHolder::findOrFail($id);            // Mark holder as archived            $holder->is_archived = 1;            $holder->save();            // Archive related assignments and copies for data integrity            AgricultureHolderSystem::where('agriculture_holder_id', $holder->id)->update(['is_archived' => 1]);            AgricultureSharedHolder::where('agriculture_holder_id', $holder->id)->update(['is_archived' => 1]);            AgricultureHolderDonor::where('agriculture_holder_id', $holder->id)->update(['is_archived' => 1]);            AgricultureSystemComponentHolder::where('agriculture_holder_id', $holder->id)->update(['is_archived' => 1]);            DB::commit();            if (request()->ajax()) {                return response()->json([                    'success' => true,                    'message' => 'Agriculture holder archived successfully.'                ]);            }            return redirect()->route('argiculture-user.index')                ->with('message', 'Agriculture holder archived successfully.');        } catch (\Exception $e) {            DB::rollBack();            if (request()->ajax()) {                return response()->json([                    'success' => false,                    'message' => 'Error deleting holder: ' . $e->getMessage()                ], 500);            }            return back()->with('error', 'Error deleting Agriculture Holder: ' . $e->getMessage());        }    }    /**     * Revert a confirmed holder back to Requested status     */    public function revertToRequested(Request $request, $id)    {        if (!Auth::guard('user')->user()) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'Unauthorized'], 401);            }            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Authorization        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'You do not have permission to revert agriculture holders.'], 403);            }            return back()->with('error', 'You do not have permission to revert agriculture holders.');        }        try {            DB::beginTransaction();            $holder = AgricultureHolder::findOrFail($id);            $requestedStatus = AgricultureHolderStatus::firstOrCreate(                ['english_name' => 'Requested'],                ['english_name' => 'Requested', 'arabic_name' => 'مطلوب', 'comet_id' => 'AGR_STATUS_REQ_' . time()]            );            $holder->agriculture_holder_status_id = $requestedStatus->id;            // Clear confirmation/completed dates when reverting            $holder->confirmation_date = null;            $holder->completed_date = null;            $holder->save();            DB::commit();            if ($request->ajax()) {                return response()->json(['success' => true, 'message' => 'Holder reverted to Requested.']);            }            return redirect()->route('argiculture-user.index')->with('message', 'Holder reverted to Requested.');        } catch (\Exception $e) {            DB::rollBack();            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'Error reverting holder: ' . $e->getMessage()], 500);            }            return back()->with('error', 'Error reverting holder: ' . $e->getMessage());        }    }    /**     * Get agriculture users by community (AJAX endpoint)     *     * @param  int  $community_id     * @return \Illuminate\Http\JsonResponse     */    public function getAgricultureUsersByCommunity($community_id)    {        if (!Auth::guard('user')->user()) {            return response()->json(['error' => 'Unauthorized'], 401);        }        try {