n_array($userType, [1, 2, 14, 15])) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'You do not have permission to approve agriculture holders.'], 403);            }            return back()->with('error', 'You do not have permission to approve agriculture holders.');        }        try {            DB::beginTransaction();                        // Find the agriculture holder            $holder = AgricultureHolder::findOrFail($id);                        // Find or create the "Confirmed" status            $confirmedStatus = AgricultureHolderStatus::firstOrCreate(                ['english_name' => 'Confirmed'],                [                    'english_name' => 'Confirmed',                    'arabic_name' => 'مؤكد',                    'comet_id' => 'AGR_STATUS_CONF_' . time()                ]            );                        // Update holder status to confirmed            $holder->update([                'agriculture_holder_status_id' => $confirmedStatus->id,                'confirmation_date' => now()            ]);                        DB::commit();                        if ($request->ajax()) {                return response()->json([                    'success' => true,                     'message' => 'Agriculture holder approved successfully and moved to confirmed status.'                ]);            }                        return redirect()->route('argiculture-user.index')                ->with('message', 'Agriculture holder approved successfully and moved to confirmed status.');                        } catch (\Exception $e) {            DB::rollBack();                        if ($request->ajax()) {                return response()->json([                    'success' => false,                     'message' => 'Error approving holder: ' . $e->getMessage()                ], 500);            }                        return back()->with('error', 'Error approving agriculture holder: ' . $e->getMessage());        }    }    /**     * Reject holder - change status to rejected     */    public function reject(Request $request, $id)    {        if (!Auth::guard('user')->user()) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'Unauthorized'], 401);            }            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'You do not have permission to reject agriculture holders.'], 403);            }            return back()->with('error', 'You do not have permission to reject agriculture holders.');        }        try {            DB::beginTransaction();                        // Find the agriculture holder            $holder = AgricultureHolder::findOrFail($id);                        // Find or create the "Rejected" status            $rejectedStatus = AgricultureHolderStatus::firstOrCreate(                ['english_name' => 'Rejected'],                [                    'english_name' => 'Rejected',                    'arabic_name' => 'مرفوض',                    'comet_id' => 'AGR_STATUS_REJ_' . time()                ]            );                        // Update holder status to rejected            $holder->update([                'agriculture_holder_status_id' => $rejectedStatus->id            ]);                        DB::commit();                        if ($request->ajax()) {                return response()->json([                    'success' => true,                     'message' =>