ture holder as complete: ' . $e->getMessage());        }    }    /**     * Download all QR codes as a ZIP file (generates missing QR svgs where needed).     */    public function downloadAllQrcodes(Request $request)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            return back()->with('error', 'You do not have permission to download QR codes.');        }        try {            // Only include holders currently in progress            $holders = AgricultureHolder::with(['community', 'household'])                ->whereHas('agricultureHolderStatus', function($q) {                    $q->where('english_name', 'In Progress');                })                ->get();            $files = [];            $dir = storage_path('app/public/agriculture_qrcodes');            if (!file_exists($dir)) {                mkdir($dir, 0755, true);            }            $renderer = new ImageRenderer(new RendererStyle(300), new SvgImageBackEnd());            $writer = new Writer($renderer);            foreach ($holders as $holder) {                $path = $holder->qrcode_path;                if (empty($path) || !Storage::disk('public')->exists($path)) {                    $text = route('argiculture-user.show', $holder->id);                    $svg = $writer->writeString($text);                    $holderName = optional($holder->household)->english_name ?? ('holder_' . $holder->id);                    $communityName = optional($holder->community)->english_name ?? (optional($holder->community)->name ?? 'community');                    $holderSlug = $this->sanitizeFileNameComponent($holderName);                    $communitySlug = $this->sanitizeFileNameComponent($communityName);                    $filename = 'holder_' . $holderSlug . '_' . $communitySlug . '_' . $holder->id . '_' . time() . '.svg';                    $path = 'agriculture_qrcodes/' . $filename;                    Storage::disk('public')->put($path, $svg);                    $holder->qrcode_path = $path;                    $holder->save();                }                if (Storage::disk('public')->exists($path)) {                    $files[] = storage_path('app/public/' . $path);                }            }            if (empty($files)) {                return back()->with('error', 'No QR files available to download for holders with status In Progress.');            }            $zipName = 'agriculture_qrcodes_' . date('Ymd_His') . '.zip';            $zipDir = storage_path('app/public/temp');            if (!file_exists($zipDir)) mkdir($zipDir, 0755, true);            $zipFullPath = $zipDir . '/' . $zipName;            $zip = new \ZipArchive();            if ($zip->open($zipFullPath, \ZipArchive::CREATE | \ZipArchive::OVERWRITE) !== true) {                return back()->with('error', 'Could not create zip archive.');            }            foreach ($files as $file) {                if (file_exists($file)) {                    $zip->addFile($file, basename($file));                }            }            $zip->close();            return response()->download($zipFullPath)->deleteFileAfterSend(true);        } catch (\Exception $e) {            return back()->with('error', 'Error creating QR zip: ' . $e->getMessage());        }    }    /**     * Show edit form for a holder's assigned system components (allows per-holder overrides)     */    public function editSystemComponents($holderId, $systemId)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        try {            $holder = AgricultureHolder::findOrFail($holderId);            $system = AgricultureSystem::findOrFail($systemId);            // get system components (resilient to column names)            try {                $columns = \Schema::getColumnListing('agriculture_system_components');            } catch (\Exception $e) {                $columns = [];            }            $systemCol = null; $componentCol = null; $modelCol = null; $quantityCol = null; $unitPriceCol = null; $archivedCol = null;            foreach ($columns as $col) {                $lc = strtolower($col);                if (!$systemCol && str_contains($lc, 'system') && str_ends_with($lc, '_id')) $systemCol = $col;                if (!$componentCol && str_contains($lc, 'component') && str_ends_with($lc, '_id')) $componentCol = $col;                if (!$modelCol && str_contains($lc, 'model') && str_ends_with($lc, '_id')) $modelCol = $col;                if (!$quantityCol && ($lc === 'quantity' || str_contains($lc, 'qty'))) $quantityCol = $col;                if (!$unitPriceCol && (str_contains($lc, 'unit_price') || str_contains($lc, 'unitprice') || str_contains($lc, 'unit'))) $unitPriceCol = $col;                if (!$archivedCol && ($lc === 'is_archived' || $lc === 'archived')) $archivedCol = $col;            }            $systemCol = $systemCol ?? 'agriculture_system_id';            $componentCol = $componentCol ?? 'agriculture_component_id';            $modelCol = $modelCol ?? 'agriculture_component_model_id';            $quantityCol = $quantityCol ?? 'quantity';            $unitPriceCol = $unitPriceCol ?? 'unit_price';            $archivedCol = $archivedCol ?? 'is_archived';            $rows = \DB::table('agriculture_system_components as asc')                ->where("asc.{$systemCol}", $system->id)                ->where("asc.{$archivedCol}", 0)                ->get();            $components = collect($rows)->map(function($r) use ($componentCol, $modelCol, $quantityCol, $unitPriceCol) {                return [                    'system_component_id' => $r->id,                    'component_id' => $r->{$componentCol} ?? null,                    'model_id' => $r->{$modelCol} ?? null,                    'quantity' => $r->{$quantityCol} ?? null,                    'unit_price' => $r->{$unitPriceCol} ?? null,                ];            })->values();            // load any existing holder-specific copies            $holderCopies = AgricultureSystemComponentHolder::where('agriculture_holder_id', $holder->id)                ->whereIn('agriculture_system_component_id', $components->pluck('system_component_id')->toArray())                ->get()->keyBy('agriculture_system_component_id');            // merge values for view            $merged = $components->map(function($c) use ($holderCopies) {                $hc = $holderCopies->get($c['system_component_id']);                return [                    'system_component_id' => $c['system_component_id'],                    'holder_component_id' => $hc ? $hc->id : null,                    'component_id' => $c['component_id'],                    'model_id' => $c['model_id'],                    'quantity' => $hc ? $hc->quantity : $c['quantity'],                    'unit_price' => $hc ? $hc->unit_price : $c['unit_price'],                ];            });            return view('agriculture.user.edit-system-components', compact('holder', 'system', 'merged'));        } catch (\Exception $e) {            return back()->with('error', 'Error loading components: ' . $e->getMessage());        }    }    /**     * Update holder-specific system components (create or update copies)     */    public function updateSystemComponents(Request $request, $holderId, $systemId)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        $request->validate([            'system_component_id' => 'required|array',            'system_component_id.*' => 'required|integer',            'quantity' => 'array',            'unit_price' => 'array',            'holder_component_id' => 'array'        ]);        try {            $holder = AgricultureHolder::findOrFail($holderId);            $scIds = $request->input('system_component_id', []);            $quantities = $request->input('quantity', []);            $unitPrices = $request->input('unit_price', []);            $holderIds = $request->input('holder_component_id', []);            foreach ($scIds as $i => $scId) {                $qty = isset($quantities[$i]) ? $quantities[$i] : null;                $up = isset($unitPrices[$i]) ? $unitPrices[$i] : null;                $hcId = isset($holderIds[$i]) ? $holderIds[$i] : null;                if ($hcId) {                    $hc = AgricultureSystemComponentHolder::find($hcId);                    if ($hc) {                        $hc->quantity = $qty;                        $hc->unit_price = $up;                        $hc->is_archived = 0;                        $hc->save();                    }                } else {                    // create new holder copy only if values provided (or create blank copy to allow future edits)                    AgricultureSystemComponentHolder::create([                        'agriculture_system_component_id' => $scId,                        'agriculture_holder_id' => $holder->id,                        'agriculture_system_id' => $systemId,                        'quantity' => $qty,                        'unit_price' => $up,                        'is_archived' => 0                    ]);                }            }            return redirect()->route('argiculture-user.show', $holder->id)                ->with('message', 'Holder system components updated successfully.');        } catch (\Exception $e) {            return back()->withInput()->with('error', 'Error updating components: ' . $e->getMessage());        }    }    /**     * Delete (archive) a holder-specific component entry     */    public function destroySystemComponent(Request $request, $holderId, $systemId, $holderComponentId)    {        // Authentication        if (!Auth::guard('user')->user()) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'Unauthorized'], 401);            }            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Authorization (mirror other mutating methods)        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'You do not have permission to remove holder components.'], 403);            }            return back()->with('error', 'You do not have permission to remove holder components.');        }        try {            $hc = AgricultureSystemComponentHolder::where('id', $holderComponentId)                ->where('agriculture_holder_id', $holderId)                ->firstOrFail();            // If already archived, return success for idempotency            if (!empty($hc->is_archived)) {                if ($request->ajax()) {                    return response()->json(['success' => true, 'message' => 'Holder component already removed.']);                }                return redirect()->route('argiculture-user.show', $holderId)                    ->with('message', 'Holder component already removed.');            }            $hc->update(['is_archived' => 1]);            if ($request->ajax()) {                return response()->json(['success' => true, 'message' => 'Holder component removed.']);            }            return redirect()->route('argiculture-user.show', $holderId)                ->with('message', 'Holder component removed.');        } catch (\Exception $e) {            if ($request->ajax()) {                return response()->json(['success' => false, 'message' => 'Error removing holder component: ' . $e->getMessage()], 500);            }            return back()->with('error', 'Error removing holder component: ' . $e->getMessage());        }    }}